"""子类模型的结构无法保存和序列化，只能保持参数"""import tensorflow as tffrom tensorflow.keras import layersimport matplotlib.pyplot as plt# 构建模型class ThreeLayerMLP(tf.keras.Model):    def __init__(self, name=None):        super(ThreeLayerMLP, self).__init__(name=name)        self.dense_1 = layers.Dense(64, activation='relu')        self.dense_2 = layers.Dense(64, activation='relu')        self.pred_layer = layers.Dense(10, activation='softmax')    def call(self, inputs):        x = self.dense_1(inputs)        x = self.dense_2(x)        return self.pred_layer(x)model = ThreeLayerMLP()# 训练模型(train_x, train_y), (test_x, test_y) = tf.keras.datasets.mnist.load_data()x_train = train_x.reshape(60000, 784).astype('float32') / 255x_test = test_x.reshape(10000, 784).astype('float32') / 255model.compile(optimizer='sgd',              loss='sparse_categorical_crossentropy',              metrics=['accuracy'])model.fit(x_train,          train_y,          batch_size=64,          epochs=1,          validation_data=(x_test, test_y),          validation_freq=1)model.summary()# tf.saved_model.save(model, './model/saved_model/')model.save('./model/saved_model/')del model'''加载模型结构和参数，识别测试集中的手写数字'''plt.imshow(test_x[1], cmap='gray')plt.show()# new_model = tf.saved_model.load('./model/saved_model/')new_model = tf.keras.models.load_model('./model/saved_model/')predict = new_model(x_test)[1]print(tf.argmax(predict))